125	  const policyBasePremium = policyBasePremiumFor(input.items);
126	  const premiumWithSurcharges = policyBasePremium + itemSurchargesFor(input.items);
127	  const policyWideModifiers = policyWideModifiersFor(input, policyBasePremium);
128	  return Math.ceil(premiumWithSurcharges + policyWideModifiers + PROCESSING_FEE);
