142	  damages: ClaimDamage[];
143	}
144	
145	interface ClaimResult {
146	  payout: number;
147	  remainingCap: number;
148	}
149	
150	const DEDUCTIBLE = 100;
151	const CAP_MULTIPLIER = 2;
152	
153	const INSURANCE_VALUES: Record<string, number> = {
154	  sword: 1000,
155	  amulet: 600,
156	  staff: 800,
157	  potion: 400,
158	  rune: 250,
159	  moonstone: 250,
160	};
161	
162	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
163	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
164	
165	function isHighlyEnchanted(item: QuoteItem | undefined): boolean {
166	  return (item?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD;
167	}
168	
169	function insuredItemFor(damage: ClaimDamage, policy: ClaimPolicy): QuoteItem | undefined {
170	  return policy.items.find((item) => item.type === damage.itemType);
171	}
172	
173	function rejectNegativeDamages(incident: ClaimIncident): void {
174	  for (const damage of incident.damages) {
175	    if (damage.amount < 0) {
176	      throw new Error(`Damage amount for "${damage.itemType}" cannot be negative`);
177	    }
178	  }
179	}
180	
181	function rejectDamagesNotCoveredByPolicy(incident: ClaimIncident, policy: ClaimPolicy): void {
182	  const insuredCounts = countByType(policy.items);
183	  const damageCounts = tallyBy(incident.damages, (damage) => damage.itemType);
184	
185	  for (const [itemType, damageCount] of damageCounts) {
186	    if (damageCount > (insuredCounts.get(itemType) ?? 0)) {
187	      throw new Error(`Damage references more "${itemType}" items than the policy insures`);
188	    }
189	  }
190	}
191	
192	function validateIncident(incident: ClaimIncident, policy: ClaimPolicy): void {
193	  rejectNegativeDamages(incident);
194	  rejectDamagesNotCoveredByPolicy(incident, policy);
195	}
196	
197	function reimbursementFor(damage: ClaimDamage, policy: ClaimPolicy): number {
198	  const insuredItem = insuredItemFor(damage, policy);
199	  if (isHighlyEnchanted(insuredItem)) {
200	    return damage.amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
201	  }
202	  return damage.amount;
203	}
204	
205	function payoutFor(incident: ClaimIncident, policy: ClaimPolicy): number {
206	  let payout = 0;
207	  for (const damage of incident.damages) {
208	    payout += reimbursementFor(damage, policy) - DEDUCTIBLE;
209	  }
210	  return payout;
211	}
212	
213	function capFor(policy: ClaimPolicy): number {
214	  let insuranceTotal = 0;
215	  for (const item of policy.items) {
216	    insuranceTotal += INSURANCE_VALUES[item.type];
217	  }
218	  return CAP_MULTIPLIER * insuranceTotal;
219	}
220	
221	export function claim(
222	  policy: ClaimPolicy,
223	  incident: ClaimIncident,
224	  remainingCap?: number,
225	): ClaimResult {
226	  validateIncident(incident, policy);
227	  const rawPayout = payoutFor(incident, policy);
228	  const availableCap = remainingCap ?? capFor(policy);
229	  const payout = Math.min(rawPayout, availableCap);
230	  return { payout, remainingCap: availableCap - payout };
231	}
